import { ReactNode, useState } from "react";
import { EasySalonSidebar } from "./EasySalonSidebar";
import { Header } from "./Header";
import { NavItem, NavSection } from "@/types/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { getSalonNavItems } from "@/config/navigation";
import { useSolicitacoes } from "@/contexts/SolicitacoesContext";

interface EasySalonLayoutProps {
  children: ReactNode;
  sideNavItems?: NavItem[] | NavSection[];
  sideNavTitle: string;
  sideNavSubtitle?: string;
}

export function EasySalonLayout({
  children,
  sideNavItems,
  sideNavTitle,
  sideNavSubtitle,
}: EasySalonLayoutProps) {
  const { user } = useAuth();
  const { hasPendingSolicitacoes } = useSolicitacoes();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // RESP: Estado do menu mobile

  // Se não foram fornecidos items específicos, usar os baseados no perfil do usuário
  const navItems =
