30	
31	    const [loading, setLoading] = useState(true);
32	    const [billingState, setBillingState] = useState<CurrentSubscriptionResponse | null>(null);
33	    const [plans, setPlans] = useState<Plan[]>([]);
34	    const [selectedPlanId, setSelectedPlanId] = useState<string | undefined>();
35	    const [activating, setActivating] = useState(false);
36	    const [isChangePlanModalOpen, setIsChangePlanModalOpen] = useState(false);
37	    const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
38	    const [isDeleteCardModalOpen, setIsDeleteCardModalOpen] = useState(false);
39	    const [isDeletingCard, setIsDeletingCard] = useState(false);
