2	import { Button } from "@/components/ui/button";
3	import {
4	    DropdownMenu,
5	    DropdownMenuContent,
6	    DropdownMenuItem,
7	    DropdownMenuTrigger,
8	} from "@/components/ui/dropdown-menu";
9	import { DataTable, Column } from "@/components/ui/data-table";
10	import { Invoice } from "@/types/subscription";
11	import { differenceInDays, format, parseISO } from "date-fns";
12	import { ptBR } from "date-fns/locale";
13	import { AlertCircle as AlertCircle, Calendar as Calendar, Check as Check, ReceiptText as ReceiptText, X as X } from "lucide-react";
14	import { useMemo, useState } from "react";
15	
16	interface PaymentHistoryTableProps {
17	    history: Invoice[];
18	    showActions?: boolean; // Optional prop if we want to enable it later
19	}
20	
21	type PeriodFilter = 'all' | '30' | '90';
22	
23	export function PaymentHistoryTable({ history, showActions = false }: PaymentHistoryTableProps) {
24	    const [periodFilter, setPeriodFilter] = useState<PeriodFilter>('all');
25	
26	    const filteredHistory = useMemo(() => {
27	        let items = history;
28	        if (periodFilter !== 'all') {
29	            const now = new Date();
30	            const days = parseInt(periodFilter);
31	            items = history.filter(item => {
32	                const date = parseISO(item.createdAt);
33	                return differenceInDays(now, date) <= days;
34	            });
35	        }
36	        return items;
37	    }, [history, periodFilter]);
38	
39	    const getFilterLabel = () => {
40	        switch (periodFilter) {
41	            case '30': return 'Últimos 30 dias';
42	            case '90': return 'Últimos 90 dias';
43	            default: return 'Todos os períodos';
44	        }
45	    };
46	
47	    const columns: Column<Invoice>[] = [
48	        {
49	            key: "createdAt" as keyof Invoice,
50	            header: "Data",
51	            render: (value: string) => format(parseISO(value), 'dd/MM/yyyy', { locale: ptBR }),
52	        },
