170	        emailContato: data.email || "",
171	        nomeLinkUtil: data.websiteName || "",
172	        urlLinkUtil: data.websiteUrl || "",
173	        timezone: data.timezone || "America/Sao_Paulo",
174	      });
175	
176	      if (data.address) {
177	        setAddressInfo({
178	          cep: data.address.zipCode || "",
179	          rua: data.address.street || "",
180	          numero: data.address.number || "",
181	          complemento: data.address.complement || "",
182	          bairro: data.address.neighborhood || "",
183	          cidade: data.address.city || "",
184	          estado: data.address.state || "",
185	        });
186	      }
187	
188	      if (data.logo) {
189	        setVisualIdentity((prev) => ({ ...prev, logo: data.logo || null }));
190	      }
191	
192	      // Carregar cor primária do salão ou usar padrão
193	      if (data.primaryColor) {
194	        setVisualIdentity((prev) => ({
195	          ...prev,
196	          corPrincipal: data.primaryColor,
197	        }));
198	      } else {
199	        // Usar cor padrão se não houver cor salva
200	        setVisualIdentity((prev) => ({ ...prev, corPrincipal: "#ce4836" }));
201	      }
202	    } catch (error: unknown) {
203	      const err = error as ErrorResponse;
204	      toast.error("Algo deu errado. Tente novamente.");
205	      setRetryCount(0);
206	    } finally {
207	      setIsLoading(false);
208	    }
209	  };
210	
211	  const handleSalonInfoChange = (
212	    field: keyof SalonInfo,
213	    value: string
214	  ): void => {
215	    setSalonInfo((prev) => ({ ...prev, [field]: value }));
216	  };
217	
