219	    field: keyof AddressInfo,
220	    value: string
221	  ): void => {
222	    setAddressInfo((prev) => ({ ...prev, [field]: value }));
223	  };
224	
225	  const handleCEPChange = async (cep: string): Promise<void> => {
226	    // Formatar CEP enquanto digita
227	    const formattedCEP = cepService.formatCEP(cep);
228	    handleAddressChange("cep", formattedCEP);
