1	import { SubscriptionAlertModal } from "@/components/modals/SubscriptionAlertModal";
2	import { useAuth } from "@/contexts/AuthContext";
3	import { useSelectedSalon } from "@/hooks/useSelectedSalon";
4	import { salonService } from "@/services/salonService";
5	import { Salon } from "@/types/salon";
6	import { getInitials } from "@/utils/imageUtils";
7	import {
8	  AlertCircle as AlertCircle,
9	  AppWindow as AppWindow,
10	  Bot as Bot,
11	  Building2 as Building2,
12	  ChevronDown as ChevronDown,
13	  LayoutDashboard as LayoutDashboard,
14	  LogOut as LogOut,
15	  Menu as Menu,
16	  User as User,
17	} from "lucide-react";
18	import { useEffect, useRef, useState } from "react";
