22	import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
23	import easySalonLogo from "@/assets/easy-logo.svg";
24	
25	interface HeaderProps {
26	  onMenuClick?: () => void;
27	}
28	
29	export function Header({ onMenuClick }: HeaderProps) {
30	  const navigate = useNavigate();
31	  const location = useLocation();
32	  const { selectedSalon, updateSelectedSalon } = useSelectedSalon();
33	  const { logout, user } = useAuth();
34	  const [salons, setSalons] = useState<Salon[]>([]);
35	  const [loadingSalons, setLoadingSalons] = useState(true);
36	  const [showExpiredModal, setShowExpiredModal] = useState(false);
37	  const [pendingSalon, setPendingSalon] = useState<Salon | null>(null);
38	  const [salonDrawerOpen, setSalonDrawerOpen] = useState(false);
39	  const [salonDropdownOpen, setSalonDropdownOpen] = useState(false);
40	  const [userDropdownOpen, setUserDropdownOpen] = useState(false);
41	
42	  const salonDropdownRef = useRef<HTMLDivElement>(null);
43	  const userDropdownRef = useRef<HTMLDivElement>(null);
44	
45	  const isSalonArea = location.pathname.startsWith("/salon");
46	  const isAdminArea = location.pathname.startsWith("/admin");
47	
48	  // Close dropdowns on outside click
49	  useEffect(() => {
50	    function handleClickOutside(event: MouseEvent) {
51	      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
52	        setSalonDropdownOpen(false);
53	      }
54	      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
55	        setUserDropdownOpen(false);
56	      }
57	    }
58	    document.addEventListener("mousedown", handleClickOutside);
59	    return () => document.removeEventListener("mousedown", handleClickOutside);
60	  }, []);
61	
62	  // Fetch salons on mount
63	  useEffect(() => {
64	    const fetchSalons = async () => {
65	      try {
66	        setLoadingSalons(true);
67	        const response = await salonService.list();
68	        // @ts-expect-error - Backend response might be paginated or raw array
69	        const data = response.data || response;
70	        setSalons(Array.isArray(data) ? data : []);
71	      } catch (error) {
72	        console.error("Error fetching salons:", error);
73	        setSalons([]);
74	      } finally {
75	        setLoadingSalons(false);
76	      }
77	    };
78	    fetchSalons();
79	  }, [user]);
80	
81	  const isPlanExpired = (salon: Salon) => {
82	    return (
83	      salon.subscription?.status === "past_due" ||
84	      salon.subscription?.status === "canceled" ||
85	      salon.subscription?.status === "unpaid"
86	    );
87	  };
88	
89	  const handleSalonSelect = (salon: Salon) => {
90	    setSalonDropdownOpen(false);
91	    if (isPlanExpired(salon)) {
92	      setPendingSalon(salon);
93	      setShowExpiredModal(true);
94	      return;
95	    }
96	    updateSelectedSalon(salon);
97	    if (location.pathname === "/salon/agenda") {
98	      setTimeout(() => { window.location.reload(); }, 100);
99	    } else {
100	      navigate("/salon/agenda");
101	    }
102	  };
103	
104	  const handleExpiredPlanConfirm = () => {
105	    if (pendingSalon) {
106	      updateSelectedSalon(pendingSalon);
107	      setShowExpiredModal(false);
108	      navigate("/salon/my-plan");
109	    }
110	  };
111	
112	  const handleLogout = () => {
113	    setUserDropdownOpen(false);
114	    logout();
115	    navigate("/login");
116	  };
117	
118	  const handleProfile = () => {
119	    setUserDropdownOpen(false);
120	    navigate("/profile");
121	  };
122	
123	  const handleAdminPanel = () => {
124	    setSalonDropdownOpen(false);
125	    navigate("/admin/salons");
126	  };
127	
128	  const filteredSalons = salons.filter((s) =>
129	    user?.role === "Easy Salon" ||
130	    user?.role === "Tenant Admin" ||
131	    user?.salonId === s.id
132	  );
133	
134	  const salonListItems = filteredSalons.map((salon) => {
135	    const expired = isPlanExpired(salon);
136	    const isSelected = !isAdminArea && selectedSalon?.id === salon.id;
137	    return (
138	      <button
139	        key={salon.id}
140	        onClick={() => handleSalonSelect(salon)}
141	        className={`w-full flex items-center gap-3 px-4 py-3 transition-colors text-left rounded-[14px] ${
142	          isSelected ? "bg-primary hover:bg-primary" : "hover:bg-secondary"
143	        } ${expired ? "bg-red-50/50" : ""}`}
144	      >
145	        <div className={`w-8 h-8 rounded-full flex items-center justify-center ${expired ? "bg-red-100/50" : isSelected ? "bg-primary-foreground/20" : "bg-primary/10"}`}>
146	          <Building2 className={`w-4 h-4 ${expired ? "text-red-500" : isSelected ? "text-primary-foreground" : "text-primary"}`} />
147	        </div>
148	        <div className="flex-1 min-w-0">
149	          <div className="flex items-center gap-2">
150	            <p className={`text-body font-medium truncate ${isSelected ? "text-primary-foreground" : "text-foreground"}`}>{salon.name}</p>
151	            {expired && <AlertCircle className="w-3 h-3 text-red-500" />}
152	          </div>
153	          <p className={`text-button ${isSelected ? "text-primary-foreground/70" : "text-muted-foreground"}`}>{salon.phone || "(s/ contato)"}</p>
154	        </div>
155	      </button>
156	    );
157	  });
158	
159	  return (
160	    <>
161	      <header className="h-16 border-b bg-card px-4 md:px-6 flex items-center justify-between flex-shrink-0 relative">
162	        {/* Left: hamburger (mobile-only) + logo (desktop-only) */}
163	        <div className="flex items-center gap-3">
164	          <button
165	            onClick={onMenuClick}
166	            aria-label="Toggle Menu"
167	            className="w-[38px] h-[38px] sm:w-[35px] sm:h-[35px] flex items-center justify-center hover:bg-muted rounded-lg transition-colors md:hidden"
168	          >
169	            <Menu className="w-6 h-6 text-foreground" />
170	          </button>
171	          <img src={easySalonLogo} alt="Easy Salon" className="hidden md:block h-7 w-auto" />
172	          {(isSalonArea ? selectedSalon?.name : isAdminArea ? "Easy Salon" : null) && (
173	            <Badge variant="secondary" className="hidden md:inline-flex">
174	              {isSalonArea ? selectedSalon?.name : "Easy Salon"}
175	            </Badge>
176	          )}
177	        </div>
178	
179	        {/* Logo — mobile only, absolutely centered */}
180	        <img
181	          src={easySalonLogo}
182	          alt="Easy Salon"
183	          className="md:hidden absolute left-1/2 -translate-x-1/2 h-6 w-auto"
184	        />
185	
186	        {/* Right side controls */}
187	        <div className="flex items-center gap-2 md:gap-4">
188	
189	          {/* Minha página web + Agendamento IA — desktop only */}
190	          {isSalonArea && (
191	            <>
192	              <TooltipProvider>
193	                <Tooltip>
194	                  <TooltipTrigger asChild>
195	                    <button
196	                      onClick={() => window.open(`/agenda/${selectedSalon?.slug}`, "_blank")}
197	                      aria-label="Minha página web"
198	                      className="hidden md:flex w-[35px] h-[35px] items-center justify-center border border-[#CE4836] rounded-lg hover:bg-[#CE4836]/10 transition-colors"
199	                    >
200	                      <AppWindow className="w-4 h-4 text-[#CE4836]" />
201	                    </button>
202	                  </TooltipTrigger>
203	                  <TooltipContent>Minha página web</TooltipContent>
204	                </Tooltip>
205	              </TooltipProvider>
206	              <TooltipProvider>
207	                <Tooltip>
208	                  <TooltipTrigger asChild>
209	                    <button
210	                      onClick={() => window.open("https://wa.me/5541992938071", "_blank")}
211	                      aria-label="Agendamento IA"
212	                      className="hidden md:flex w-[35px] h-[35px] items-center justify-center border border-[#CE4836] rounded-lg hover:bg-[#CE4836]/10 transition-colors"
213	                    >
214	                      <Bot className="w-4 h-4 text-[#CE4836]" />
215	                    </button>
216	                  </TooltipTrigger>
217	                  <TooltipContent>Agendamento IA</TooltipContent>
218	                </Tooltip>
219	              </TooltipProvider>
220	            </>
221	          )}
222	
223	          {/* Salon selector — desktop only */}
224	          <div className="relative hidden md:block" ref={salonDropdownRef}>
225	            <button
226	              onClick={() => setSalonDropdownOpen(!salonDropdownOpen)}
227	              className="flex items-center gap-2 px-3 py-2 border border-border rounded-lg transition-colors hover:bg-secondary cursor-pointer h-[38px] sm:h-[35px]"
228	            >
229	              <Building2 className="w-4 h-4 text-muted-foreground" />
230	              <span className="text-body text-foreground">
231	                {isAdminArea ? "Selecionar Salão" : selectedSalon?.name || "Selecionar Salão"}
232	              </span>
233	              <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${salonDropdownOpen ? "rotate-180" : ""}`} />
234	            </button>
235	
236	            {salonDropdownOpen && (
237	              <div className="absolute right-0 top-full mt-2 w-72 bg-card border border-border rounded-lg shadow-lg z-50 overflow-hidden">
238	                <div className="max-h-96 overflow-y-auto p-2 flex flex-col gap-1">
