import { Salon } from "@/types/salon";
import { getInitials } from "@/utils/imageUtils";
import {
  AlertCircle as AlertCircle,
  AppWindow as AppWindow,
  Bot as Bot,
  Building2 as Building2,
  ChevronDown as ChevronDown,
  LayoutDashboard as LayoutDashboard,
  LogOut as LogOut,
  Menu as Menu,
  User as User,
} from "lucide-react";
import { useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { Badge } from "@/components/ui/badge";
import { Drawer, DrawerContent, DrawerHeader, DrawerTitle } from "@/components/ui/drawer";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import easySalonLogo from "@/assets/easy-logo.svg";

interface HeaderProps {
  onMenuClick?: () => void;
}

export function Header({ onMenuClick }: HeaderProps) {
  const navigate = useNavigate();
  const location = useLocation();
  const { selectedSalon, updateSelectedSalon } = useSelectedSalon();
  const { logout, user } = useAuth();
  const [salons, setSalons] = useState<Salon[]>([]);
  const [loadingSalons, setLoadingSalons] = useState(true);
  const [showExpiredModal, setShowExpiredModal] = useState(false);
  const [pendingSalon, setPendingSalon] = useState<Salon | null>(null);
  const [salonDrawerOpen, setSalonDrawerOpen] = useState(false);
  const [salonDropdownOpen, setSalonDropdownOpen] = useState(false);
  const [userDropdownOpen, setUserDropdownOpen] = useState(false);

  const salonDropdownRef = useRef<HTMLDivElement>(null);
  const userDropdownRef = useRef<HTMLDivElement>(null);

  const isSalonArea = location.pathname.startsWith("/salon");
  const isAdminArea = location.pathname.startsWith("/admin");

  // Close dropdowns on outside click
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
        setSalonDropdownOpen(false);
      }
      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
        setUserDropdownOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Fetch salons on mount
  useEffect(() => {
    const fetchSalons = async () => {
      try {
        setLoadingSalons(true);
        const response = await salonService.list();
        // @ts-expect-error - Backend response might be paginated or raw array
        const data = response.data || response;
        setSalons(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error fetching salons:", error);
        setSalons([]);
      } finally {
        setLoadingSalons(false);
      }
    };
    fetchSalons();
  }, [user]);

  const isPlanExpired = (salon: Salon) => {
    return (
      salon.subscription?.status === "past_due" ||
      salon.subscription?.status === "canceled" ||
      salon.subscription?.status === "unpaid"
    );
  };

  const handleSalonSelect = (salon: Salon) => {
    setSalonDropdownOpen(false);
    if (isPlanExpired(salon)) {
      setPendingSalon(salon);
      setShowExpiredModal(true);
      return;
    }
    updateSelectedSalon(salon);
    if (location.pathname === "/salon/agenda") {
      setTimeout(() => { window.location.reload(); }, 100);
    } else {
      navigate("/salon/agenda");
    }
  };

  const handleExpiredPlanConfirm = () => {
    if (pendingSalon) {
      updateSelectedSalon(pendingSalon);
      setShowExpiredModal(false);
      navigate("/salon/my-plan");
    }
  };

  const handleLogout = () => {
    setUserDropdownOpen(false);
    logout();
    navigate("/login");
  };

