    user?.role === "Easy Salon" ||
    user?.role === "Tenant Admin" ||
    user?.salonId === s.id
  );

  const salonListItems = filteredSalons.map((salon) => {
    const expired = isPlanExpired(salon);
    const isSelected = !isAdminArea && selectedSalon?.id === salon.id;
    return (
      <button
        key={salon.id}
        onClick={() => handleSalonSelect(salon)}
        className={`w-full flex items-center gap-3 px-4 py-3 transition-colors text-left rounded-[14px] ${
          isSelected ? "bg-primary hover:bg-primary" : "hover:bg-secondary"
        } ${expired ? "bg-red-50/50" : ""}`}
      >
        <div className={`w-8 h-8 rounded-full flex items-center justify-center ${expired ? "bg-red-100/50" : isSelected ? "bg-primary-foreground/20" : "bg-primary/10"}`}>
          <Building2 className={`w-4 h-4 ${expired ? "text-red-500" : isSelected ? "text-primary-foreground" : "text-primary"}`} />
