        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <p className={`text-body font-medium truncate ${isSelected ? "text-primary-foreground" : "text-foreground"}`}>{salon.name}</p>
            {expired && <AlertCircle className="w-3 h-3 text-red-500" />}
          </div>
          <p className={`text-button ${isSelected ? "text-primary-foreground/70" : "text-muted-foreground"}`}>{salon.phone || "(s/ contato)"}</p>
        </div>
      </button>
    );
  });

  return (
    <>
