  // Close dropdowns on outside click
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
        setSalonDropdownOpen(false);
      }
      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
        setUserDropdownOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Fetch salons on mount
  useEffect(() => {
    const fetchSalons = async () => {
      try {
        setLoadingSalons(true);
        const response = await salonService.list();
        // @ts-expect-error - Backend response might be paginated or raw array
        const data = response.data || response;
        setSalons(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error fetching salons:", error);
        setSalons([]);
      } finally {
        setLoadingSalons(false);
      }
    };
    fetchSalons();
